// // This module implements a 8-bit register with load and clear functionality.
// It loads the input data on each negative edge of the clock when the load signal is high
// and clears the output data to 1 when the reset signal is activated.
module register (
    input wire rst_n,
    input wire clk,
    input wire load,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);

always @(posedge clk) begin
    if (!rst_n)
        data_out <= 8'b00000000;
    else if (load)
        data_out <= data_in;
end

endmodule

